   302	void RangerROSMessenger::UpdateOdometry(double linear, double angular,
   303	                                        double steering_angle, double dt) {
   304	  // update odometry calculations
   305	  if (motion_mode_ == MotionState::MOTION_MODE_DUAL_ACKERMAN) {
   306	    DualAckermanModel::state_type x = {position_x_, position_y_, theta_};
   307	    DualAckermanModel::control_type u;
   308	    u.v = linear;
   309	    u.phi = steering_angle;
   310	
   311	    boost::numeric::odeint::integrate_const(
   312	        boost::numeric::odeint::runge_kutta4<DualAckermanModel::state_type>(),
   313	        DualAckermanModel(robot_params_.wheelbase, robot_params_.track, u), x,
   314	        0.0, dt, (dt / 10.0));
   315	
   316	    position_x_ = x[0];
   317	    position_y_ = x[1];
   318	    theta_ = x[2];
   319	  } else if (motion_mode_ == MotionState::MOTION_MODE_PARALLEL ||
   320	             motion_mode_ == MotionState::MOTION_MODE_SIDE_SLIP) {
   321	    ParallelModel::state_type x = {position_x_, position_y_, theta_};
   322	    ParallelModel::control_type u;
   323	    u.v = linear;
   324	    if (motion_mode_ == MotionState::MOTION_MODE_SIDE_SLIP) {
   325	      u.phi = M_PI / 2.0;
   326	    } else {
   327	      u.phi = steering_angle;
   328	    }
   329	    boost::numeric::odeint::integrate_const(
   330	        boost::numeric::odeint::runge_kutta4<ParallelModel::state_type>(),
   331	        ParallelModel(u), x, 0.0, dt, (dt / 10.0));
   332	
   333	    position_x_ = x[0];
   334	    position_y_ = x[1];
   335	    theta_ = x[2];
   336	  } else if (motion_mode_ == MotionState::MOTION_MODE_SPINNING) {
   337	    SpinningModel::state_type x = {position_x_, position_y_, theta_};
   338	    SpinningModel::control_type u;
   339	    u.w = angular;
   340	
   341	    boost::numeric::odeint::integrate_const(
   342	        boost::numeric::odeint::runge_kutta4<SpinningModel::state_type>(),
   343	        SpinningModel(u), x, 0.0, dt, (dt / 10.0));
   344	
   345	    position_x_ = x[0];
   346	    position_y_ = x[1];
   347	    theta_ = x[2];
   348	  }
   349	
   350	  // update odometry topics
   351	  geometry_msgs::Quaternion odom_quat = tf::createQuaternionMsgFromYaw(theta_);
   352	
   353	  // ROS_INFO("Pose: %f, %f, %f", position_x_, position_y_, theta_ / 3.14 *
   354	  // 180.0);
   355	
   356	  // publish odometry and tf messages
   357	  nav_msgs::Odometry odom_msg;
   358	  odom_msg.header.stamp = current_time_;
   359	  odom_msg.header.frame_id = odom_frame_;
   360	  odom_msg.child_frame_id = base_frame_;
   361	
   362	  odom_msg.pose.pose.position.x = position_x_;
   363	  odom_msg.pose.pose.position.y = position_y_;
   364	  odom_msg.pose.pose.position.z = 0.0;
   365	  odom_msg.pose.pose.orientation = odom_quat;
   366	
   367	  if (motion_mode_ == MotionState::MOTION_MODE_DUAL_ACKERMAN) {
   368	    odom_msg.twist.twist.linear.x = linear;
   369	    odom_msg.twist.twist.linear.y = 0.0;
   370	    if (steering_angle == 0) {
   371	      odom_msg.twist.twist.angular.z = 0;
   372	    } else {
   373	      odom_msg.twist.twist.angular.z =
   374	          (steering_angle / std::abs(steering_angle)) * 2 * linear /
   375	          (robot_params_.wheelbase / std::abs(std::tan(steering_angle)) +
   376	           robot_params_.track);
   377	    }
   378	  } else if (motion_mode_ == MotionState::MOTION_MODE_PARALLEL ||
   379	             motion_mode_ == MotionState::MOTION_MODE_SIDE_SLIP) {
   380	    double phi = steering_angle;
   381	
   382	    if (motion_mode_ == MotionState::MOTION_MODE_SIDE_SLIP) {
   383	      phi = M_PI / 2.0;
   384	    }
   385	    odom_msg.twist.twist.linear.x = linear * std::cos(phi);
   386	    odom_msg.twist.twist.linear.y = linear * std::sin(phi);
   387	
   388	    odom_msg.twist.twist.angular.z = 0;
   389	  } else if (motion_mode_ == MotionState::MOTION_MODE_SPINNING) {
   390	    odom_msg.twist.twist.linear.x = 0;
   391	    odom_msg.twist.twist.linear.y = 0;
   392	    odom_msg.twist.twist.angular.z = angular;
   393	  }
   394	
   395	  odom_pub_.publish(odom_msg);
   396	
   397	  // // publish tf transformation
   398	  if (publish_odom_tf_) {
   399	    geometry_msgs::TransformStamped tf_msg;
   400	    tf_msg.header.stamp = current_time_;
   401	    tf_msg.header.frame_id = odom_frame_;
   402	    tf_msg.child_frame_id = base_frame_;
   403	
   404	    tf_msg.transform.translation.x = position_x_;
   405	    tf_msg.transform.translation.y = position_y_;
   406	    tf_msg.transform.translation.z = 0.0;
   407	    tf_msg.transform.rotation = odom_quat;
   408	
   409	    tf_broadcaster_.sendTransform(tf_msg);
   410	  }
   411	}
