   413	void RangerROSMessenger::TwistCmdCallback(
   414	    const geometry_msgs::Twist::ConstPtr& msg) {
   415	  double steer_cmd;
   416	  double radius;
   417	
   418	  // analyze Twist msg and switch motion_mode
   419	  // check for parking mode, only applicable to RangerMiniV2
   420	  if (parking_mode_ && robot_type_ == RangerSubType::kRangerMiniV2) {
   421	    return;
   422	  } else if (msg->linear.y != 0) {
   423	    if (msg->linear.x == 0.0 && robot_type_ == RangerSubType::kRangerMiniV1) {
   424	      motion_mode_ = MotionState::MOTION_MODE_SIDE_SLIP;
   425	      robot_->SetMotionMode(MotionState::MOTION_MODE_SIDE_SLIP);
   426	    } else {
   427	      motion_mode_ = MotionState::MOTION_MODE_PARALLEL;
   428	      robot_->SetMotionMode(MotionState::MOTION_MODE_PARALLEL);
   429	    }
   430	  } else {
   431	    steer_cmd = CalculateSteeringAngle(*msg, radius);
   432	    // Use minimum turn radius to switch between dual ackerman and spinning mode
   433	    if (radius < robot_params_.min_turn_radius) {
   434	      motion_mode_ = MotionState::MOTION_MODE_SPINNING;
   435	      robot_->SetMotionMode(MotionState::MOTION_MODE_SPINNING);
   436	    } else {
   437	      motion_mode_ = MotionState::MOTION_MODE_DUAL_ACKERMAN;
   438	      robot_->SetMotionMode(MotionState::MOTION_MODE_DUAL_ACKERMAN);
   439	    }
   440	  }
   441	
   442	  // send motion command to robot
   443	  switch (motion_mode_) {
   444	    case MotionState::MOTION_MODE_DUAL_ACKERMAN: {
   445	      if (steer_cmd > robot_params_.max_steer_angle_ackermann) {
   446	        steer_cmd = robot_params_.max_steer_angle_ackermann;
   447	      }
   448	      if (steer_cmd < -robot_params_.max_steer_angle_ackermann) {
   449	        steer_cmd = -robot_params_.max_steer_angle_ackermann;
