   530	double RangerROSMessenger::CalculateSteeringAngle(geometry_msgs::Twist msg,
   531	                                                  double& radius) {
   532	  double linear = std::abs(msg.linear.x);
   533	  double angular = std::abs(msg.angular.z);
   534	
   535	  // Circular motion
   536	  radius = linear / angular;
   537	  int k = (msg.angular.z * msg.linear.x) >= 0 ? 1.0 : -1.0;
   538	
   539	  double l, w, phi_i;
   540	  l = robot_params_.wheelbase;
   541	  w = robot_params_.track;
   542	  phi_i = atan((l / 2) / (radius - w / 2));
   543	  ROS_INFO("command linear: %f, steering_angle: %f", linear, k * phi_i);
   544	  return k * phi_i;
   545	}
